customCss:
@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@300;400;500;600;700&display=swap');
:root { --font-body: 'JetBrains Mono', monospace; --font-display: 'JetBrains Mono', monospace; --radius: 0px; --ambient-glow-opacity: 0.15; }

/* ═══════════════════════════════════════
   CRT EFFECTS — Scanlines + Vignette
   ═══════════════════════════════════════ */
body::after { content: ''; position: fixed; inset: 0; background: repeating-linear-gradient(0deg, transparent, transparent 1px, rgba(0,0,0,0.06) 1px, rgba(0,0,0,0.06) 2px); pointer-events: none; z-index: 9999; }
body::before { content: ''; position: fixed; inset: 0; background: radial-gradient(ellipse at center, transparent 55%, rgba(0,0,0,0.55) 100%); pointer-events: none; z-index: 9998; }

/* Global phosphor glow */
body { text-shadow: 0 0 3px rgba(51,255,0,0.3); }
h1, h2, h3, .page-title { text-shadow: 0 0 8px rgba(51,255,0,0.5), 0 0 16px rgba(51,255,0,0.15) !important; }

/* ═══════════════════════════════════════
   SIDEBAR — Terminal panel with separators
   ═══════════════════════════════════════ */
aside { border-right: 1px solid rgba(51,255,0,0.2) !important; backdrop-filter: none !important; background: #000000 !important; }
aside::after { content: ''; position: absolute; top: 0; right: 0; bottom: 0; width: 1px; background: linear-gradient(180deg, rgba(51,255,0,0.4), rgba(51,255,0,0.05) 50%, rgba(51,255,0,0.4)); pointer-events: none; }
.sidebar-logo-icon { border: 1px solid rgba(51,255,0,0.5) !important; border-radius: 0 !important; box-shadow: 0 0 6px rgba(51,255,0,0.2); }
.sidebar-logo-text { text-transform: uppercase !important; letter-spacing: 0.25em !important; font-size: 0.6rem !important; }

/* Nav items: command-line entries */
.sidebar-nav-item { border-radius: 0 !important; font-size: 0.7rem !important; letter-spacing: 0.08em; border: 1px solid transparent; }
.sidebar-nav-item:hover { border-color: rgba(51,255,0,0.15) !important; }

/* Section dividers */
.sidebar-libraries, .sidebar-personal { border-top: 1px dashed rgba(51,255,0,0.15); padding-top: 0.75rem; margin-top: 0.5rem; }
.sidebar-footer { border-top: 1px dashed rgba(51,255,0,0.2) !important; }

/* ═══════════════════════════════════════
   HERO — Green-tinted, shorter, contained
   ═══════════════════════════════════════ */
.home-hero { min-height: 55dvh !important; border-bottom: 1px solid rgba(51,255,0,0.15) !important; }
@media (min-width: 1024px) { .home-hero { min-height: 60dvh !important; } }
.home-hero img, .item-detail-hero img { filter: saturate(0) brightness(0.5) sepia(1) hue-rotate(70deg) saturate(2.5) !important; }

/* Detail hero: green tint + border */
.item-detail-hero { border-bottom: 1px solid rgba(51,255,0,0.15) !important; }

/* Hero title: smaller, terminal feel */
.home-hero h1 { font-size: 2rem !important; letter-spacing: 0.04em; }
@media (min-width: 640px) { .home-hero h1 { font-size: 2.5rem !important; } }
@media (min-width: 1024px) { .home-hero h1 { font-size: 3rem !important; } }

/* ═══════════════════════════════════════
   CARDS — Square aspect ratio, terminal borders
   ═══════════════════════════════════════ */
.media-card-image { aspect-ratio: 1 / 1 !important; border: 1px solid rgba(51,255,0,0.15) !important; border-radius: 0 !important; overflow: hidden; }
.media-card-image img { object-position: center 20% !important; }
.media-card:hover .media-card-image { border-color: rgba(51,255,0,0.6) !important; box-shadow: 0 0 12px rgba(51,255,0,0.25), 0 0 28px rgba(51,255,0,0.08) !important; }
.media-card:hover { transform: none !important; filter: brightness(1.15) !important; }

/* Card metadata */
.media-card a[class*='block px-1'] div:first-child { font-size: 0.7rem !important; letter-spacing: 0.04em; }
.media-card a[class*='block px-1'] div:last-child { font-size: 0.55rem !important; letter-spacing: 0.2em; }

/* ═══════════════════════════════════════
   SECTION ROWS — Terminal headers
   ═══════════════════════════════════════ */
.section-row h2 { font-size: 0.65rem !important; letter-spacing: 0.25em !important; text-transform: uppercase; opacity: 0.75; }
.section-row h2 span { font-size: 0.55rem !important; }

/* ═══════════════════════════════════════
   DETAIL PAGE — Terminal presentation
   ═══════════════════════════════════════ */
.page-title { text-transform: uppercase; letter-spacing: 0.06em; }
.page-shell h2 { text-transform: uppercase; letter-spacing: 0.18em; font-size: 0.65rem !important; opacity: 0.8; }

/* ═══════════════════════════════════════
   BADGES, BUTTONS & UI
   ═══════════════════════════════════════ */
.metadata-badge { border: 1px solid rgba(51,255,0,0.2) !important; border-radius: 0 !important; text-transform: uppercase; letter-spacing: 0.15em; font-size: 0.55rem !important; }

/* Buttons: outlined, hollow */
.pill { border-radius: 0 !important; }
.pill-primary { background: transparent !important; border: 1px solid #33ff00 !important; color: #33ff00 !important; box-shadow: 0 0 10px rgba(51,255,0,0.2); text-shadow: 0 0 4px rgba(51,255,0,0.4); }
.pill-primary:hover { background: rgba(51,255,0,0.08) !important; box-shadow: 0 0 18px rgba(51,255,0,0.4) !important; }
.pill-glass { border: 1px solid rgba(51,255,0,0.15) !important; border-radius: 0 !important; }
.action-circle { border-radius: 0 !important; border: 1px solid rgba(51,255,0,0.15); }

/* Tab bar: underline */
.tab-active { border-bottom: 1px solid #33ff00 !important; box-shadow: 0 1px 6px rgba(51,255,0,0.2); border-radius: 0 !important; }

/* ═══════════════════════════════════════
   GLASS & SURFACES — Bordered, no blur
   ═══════════════════════════════════════ */
.glass, .glass-subtle, .glass-dark { backdrop-filter: none !important; -webkit-backdrop-filter: none !important; border: 1px solid rgba(51,255,0,0.1) !important; border-radius: 0 !important; background: rgba(6,18,6,0.9) !important; }
.surface-panel { border: 1px solid rgba(51,255,0,0.1) !important; border-radius: 0 !important; }

/* ═══════════════════════════════════════
   INPUTS — Terminal prompt style
   ═══════════════════════════════════════ */
input, textarea, select { border: 1px solid rgba(51,255,0,0.2) !important; border-radius: 0 !important; caret-color: #33ff00 !important; background: rgba(0,0,0,0.8) !important; }
input:focus, textarea:focus, select:focus { border-color: rgba(51,255,0,0.5) !important; box-shadow: 0 0 8px rgba(51,255,0,0.15) !important; }

/* ═══════════════════════════════════════
   MOBILE HEADER — Terminal bar
   ═══════════════════════════════════════ */
.mobile-header { border-radius: 0 !important; border: 1px solid rgba(51,255,0,0.15) !important; backdrop-filter: none !important; background: rgba(0,0,0,0.95) !important; }

/* ═══════════════════════════════════════
   MISC — Progress, dots, scrollbar
   ═══════════════════════════════════════ */
.progress-fill { box-shadow: 0 0 6px rgba(51,255,0,0.5); border-radius: 0 !important; background: #33ff00 !important; }
.dot { border-radius: 0 !important; }
.dot-active { border-radius: 0 !important; }

/* Carousel arrows: square */
.home-hero button[class*='glass-subtle'] { border-radius: 0 !important; border: 1px solid rgba(51,255,0,0.2) !important; }

/* Blinking cursor on focused inputs */
@keyframes terminal-blink { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }
